class KQueue {
    int arr[100], front[10], rear[10];
public:
    KQueue() {
        for(int i=0;i<10;i++) front[i]=rear[i]=-1;
    }
    void enqueue(int qn, int val) {
        if(front[qn]==-1) front[qn]=rear[qn]=0;
        else rear[qn]++;
        arr[rear[qn]] = val;
    }
};

#include <bits/stdc++.h>
using namespace std;

void dijkstra(int V, vector<pair<int,int>> adj[], int src) {
    priority_queue<pair<int,int>, vector<pair<int,int>>, greater<>> pq;
    vector<int> dist(V, INT_MAX);
    dist[src] = 0;
    pq.push({0, src});

    while(!pq.empty()) {
        auto [d,u] = pq.top(); pq.pop();
        for(auto [v,w]: adj[u]) {
            if(dist[v] > d + w) {
                dist[v] = d + w;
                pq.push({dist[v], v});
            }
        }
    }
}
